using namespace std;

int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

int gcdSubarray(vector<int>& nums, int start, int end) {
    int result = nums[start];
    for (int i = start + 1; i <= end; i++) {
        result = gcd(result, nums[i]);
    }
    return result;
}

int maxScore(vector<int>& nums, int k) {
    int n = nums.size();
    int maxScore = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            vector<int> temp = nums;
            int remainingK = k;
            for (int x = i; x <= j; x++) {
                if (remainingK > 0) {
                    temp[x] *= 2;
                    remainingK--;
                }
            }
            int score = (j - i + 1) * gcdSubarray(temp, i, j);
            maxScore = max(maxScore, score);
        }
    }
    return maxScore;
}

int main() {
    vector<int> nums = {2, 4};
    int k = 1;
    cout << maxScore(nums, k) << endl;
    return 0;
